#!/usr/bin/env python3
# Twin Peaks Viewer — Windows / Mac / Linux
# Run:  python viewer.py
import base64, http.server, os, tempfile, threading, webbrowser
from pathlib import Path

HTML_B64    = ""
PRIMARY_B64 = ""
VS_B64      = ""

PORT = 8080

def main():
    with tempfile.TemporaryDirectory() as tmp:
        print("")
        print("╔══════════════════════════════════════════════════════╗")
        print("║           Twin Peaks Viewer                          ║")
        print("╚══════════════════════════════════════════════════════╝")
        print("")
        print("  Extracting viewer...")
        Path(tmp, "index.html"  ).write_bytes(base64.b64decode(HTML_B64))
        Path(tmp, "primary.json").write_bytes(base64.b64decode(PRIMARY_B64))
        Path(tmp, "vs.json"     ).write_bytes(base64.b64decode(VS_B64))
        print("  ✓ Ready.")
        print("")
        print(f"  Opening http://localhost:{PORT} ...")
        print("")
        print("  Press Ctrl+C to stop.")
        print("")
        os.chdir(tmp)
        handler = http.server.SimpleHTTPRequestHandler
        handler.log_message = lambda *a: None
        server = http.server.HTTPServer(("", PORT), handler)
        threading.Timer(0.8, lambda: webbrowser.open(f"http://localhost:{PORT}")).start()
        try:
            server.serve_forever()
        except KeyboardInterrupt:
            print("\n  Stopped.")

if __name__ == "__main__":
    main()
